package main

import "fmt"

type ListNode struct {
	Val  int
	Next *ListNode
}

func reverseKGroup(head *ListNode, k int) *ListNode {

	if head == nil || k <= 1 {
		return head
	}

	dummy := &ListNode{Next: head}
	pre := dummy




	for {

		tail := pre

		// 找当前组尾节点
		for i := 0; i < k && tail.Next != nil; i++ {
			tail = tail.Next
		}

		// 没有节点了
		if pre.Next == nil {
			break
		}

		nextGroup := tail.Next

		// 断开当前组
		tail.Next = nil

		headNext := pre.Next

		// 反转当前组
		pre.Next = reverseList(headNext)

		// 接回后面的链表
		headNext.Next = nextGroup

		// 移动 pre
		pre = headNext
	}

	return dummy.Next
}

func reverseList(head *ListNode) *ListNode {

	var pre *ListNode
	current := head

	for current != nil {

		temp := current.Next

		current.Next = pre

		pre = current

		current = temp
	}

	return pre
}

func buildList(nums []int) *ListNode {

	dummy := &ListNode{}
	cur := dummy

	for _, num := range nums {
		cur.Next = &ListNode{Val: num}
		cur = cur.Next
	}

	return dummy.Next
}

func printList(head *ListNode) {

	for head != nil {

		fmt.Print(head.Val)

		if head.Next != nil {
			fmt.Print(" -> ")
		}

		head = head.Next
	}

	fmt.Println()
}

func main() {

	head := buildList([]int{1, 2, 3, 4, 5, 6, 7, 8})

	k := 3

	newHead := reverseKGroup(head, k)

	printList(newHead)
}
